import React, {useState} from "react";
import { View } from "react-native";
import ColorPicker, { colorKit, HueSlider, OpacitySlider, Panel1, PreviewText, Swatches, type ColorFormatsObject } from 'reanimated-color-picker';
import type { IKitsInputColorPicker } from "@lmb/kitsconcerto-types";
import KitsContainer from "../../Helpers/FormContainer";
import { useFormInputController } from "../../Helpers/useFormInputController";
import Addons from "../../Helpers/Addons";
import { colorPickerStyle } from './colorPickerStyle';

const KitsInputColorPicker = ({ ref, ...props }: IKitsInputColorPicker) => {
    const {
        id,
        label,
        required,
        disabled,
        errors,
        invalid,
        helperText,
        value,
        defaultValue,
        onChange,
        leftAddon,
        rightAddon,
        colorFormat, // optional: may not be used directly in reanimated-color-picker
        localProps = {},
        ...rest
    } = props;

    const customSwatches = new Array(6).fill('#fff').map(() => colorKit.randomRgbColor().hex());

    const [resultColor, setResultColor] = useState(customSwatches[0]);



    // Unified controlled/uncontrolled logic
    const { value: displayValue, emitChange, onWorkletChange, currentReanimatedValue } = useFormInputController<any>({
        value,
        defaultValue,
        onChange
    });

    const onColorChange = (color: ColorFormatsObject) => {
        'worklet';
        onWorkletChange(color.hex);
    };


    return (
        <KitsContainer
            id={id}
            label={label}
            helperText={helperText}
            errors={errors}
            invalid={invalid}
            disabled={disabled}
            required={required}
        >
            <Addons leftAddon={leftAddon} rightAddon={rightAddon}>
                <View style={{ width: "100%" }}>
                    <ColorPicker
                        value={resultColor}
                        sliderThickness={25}
                        thumbSize={24}
                        thumbShape='circle'
                        onChange={onColorChange}
                        onCompleteJS={(color: ColorFormatsObject)=>emitChange(color.hex)}
                        style={colorPickerStyle.picker}
                        boundedThumb
                    >
                        <Panel1 style={colorPickerStyle.panelStyle} />
                        <HueSlider style={colorPickerStyle.sliderStyle} />
                        <OpacitySlider style={colorPickerStyle.sliderStyle} />

                        {/*<Divider />*/}
                        <Swatches
                            style={colorPickerStyle.swatchesContainer}
                            swatchStyle={colorPickerStyle.swatchStyle}
                            colors={customSwatches}
                        />
                        {/*<Divider />*/}

                        <PreviewText style={colorPickerStyle.previewTxt} colorFormat='hwba' />
                    </ColorPicker>
                </View>
            </Addons>
        </KitsContainer>
    );
};

export default KitsInputColorPicker;
